import React, { useState, useEffect } from 'react';
import { PHONE_NUMBER, EMAIL_ADDRESS } from '../constants';

export const Hero: React.FC = () => {
  const [scrollY, setScrollY] = useState(0);
  const logoUrl = "https://filedn.eu/lCrcyhrkkvYjfBEUTex82pz/Matthieu/81B744F8-354C-4635-914E-0CD7B8FAA0BC.PNG";
  const bgImageUrl = "https://filedn.eu/lCrcyhrkkvYjfBEUTex82pz/Matthieu/Gemini_Generated_Image_9bc4eo9bc4eo9bc4.png";

  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Calcul du facteur de zoom parallaxe (1 à 1.15 max pour rester élégant)
  const parallaxScale = 1 + (scrollY * 0.0003);

  return (
    <section className="relative h-[80vh] min-h-[450px] w-full flex flex-col items-center justify-center bg-white overflow-hidden pt-4">
      {/* Background avec Parallaxe Zoom */}
      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-white/92 z-10"></div>
        <div 
          className="w-full h-full will-change-transform"
          style={{ 
            transform: `scale(${parallaxScale})`,
            transition: 'transform 0.1s ease-out' 
          }}
        >
          <img 
            src={bgImageUrl} 
            alt="Atmosphère Maison Henria" 
            className="w-full h-full object-cover grayscale-[0.3] opacity-15"
          />
        </div>
      </div>

